import 'dart:async';

import 'subscription.dart';

class EventWorker {
  EventWorker(this._dispatch);

  final void Function(String) _dispatch;
  StreamSubscription<String>? _subscription;

  void start(Stream<String> source) {
    _subscription = bindSubscription(source, _dispatch);
  }

  Future<void> stop() async {
    _subscription = null;
  }
}

