import 'dart:async';

import '../lib/worker.dart';

Future<void> main() async {
  final events = <String>[];
  final controller = StreamController<String>(sync: true);
  final worker = EventWorker(events.add);
  worker.start(controller.stream);
  controller.add('first');
  if (events.join(',') != 'first') throw StateError('active worker must dispatch');
  await controller.close();
  print('public worker contract passed');
}
